 131	static bstring* _match_id(bparser *parser)
 132	{
 133	    if (next_type(parser) == TokenId) {
 134	        bstring *str = next_token(parser).u.s;
 135	        scan_next_token(parser); /* skip ID */
 136	        return str;
 137	    }
 138	    return NULL;
 139	}
