 225	/* Initialize a function block and create a new `bprotoˋ */
 226	static void begin_func(bparser *parser, bfuncinfo *finfo, bblockinfo *binfo)
 227	{
 228	    bvm *vm = parser->vm;
 229	    bproto *proto = be_newproto(vm);
 230	    var_setproto(vm->top, proto);
 231	    be_stackpush(vm);
 232	    be_vector_init(vm, &finfo->code, sizeof(binstruction)); /* vector for code, vectors are not gced */
 233	    proto->code = be_vector_data(&finfo->code);
 234	    proto->codesize = be_vector_capacity(&finfo->code);
 235	    be_vector_init(vm, &finfo->kvec, sizeof(bvalue)); /* vector for constants */
 236	    proto->ktab = be_vector_data(&finfo->kvec);
 237	    proto->nconst = be_vector_capacity(&finfo->kvec);
 238	    be_vector_init(vm, &finfo->pvec, sizeof(bproto*)); /* vector for subprotos */
 239	    proto->ptab = be_vector_data(&finfo->pvec);
 240	    proto->nproto = be_vector_capacity(&finfo->pvec);
 241	    proto->source = parser_source(parser); /* keep a copy of source for function */
 242	    finfo->local = be_list_new(vm); /* list for local variables */
 243	    var_setlist(vm->top, finfo->local); /* push list of local variables on the stack (avoid gc) */
 244	    be_stackpush(vm);
 245	    finfo->upval = be_map_new(vm); /* push a map for upvals on stack */
 246	    var_setmap(vm->top, finfo->upval);
 247	    be_stackpush(vm);
 248	    finfo->prev = parser->finfo; /* init finfo */
 249	    finfo->lexer = &parser->lexer;
 250	    finfo->proto = proto;
 251	    finfo->freereg = 0;
 252	    finfo->binfo = NULL;
 253	    finfo->pc = 0;
 254	    finfo->flags = 0;
 255	    parser->finfo = finfo;
 256	#if BE_DEBUG_RUNTIME_INFO
 257	    be_vector_init(vm, &finfo->linevec, sizeof(blineinfo));
 258	    proto->lineinfo = be_vector_data(&finfo->linevec);
 259	    proto->nlineinfo = be_vector_capacity(&finfo->linevec);
 260	#endif
 261	#if BE_DEBUG_VAR_INFO
 262	    be_vector_init(vm, &finfo->varvec, sizeof(bvarinfo));
 263	    proto->varinfo = be_vector_data(&finfo->varvec);
 264	    proto->nvarinfo = be_vector_capacity(&finfo->varvec);
 265	#endif
 266	    begin_block(finfo, binfo, 0);
 267	}
