1420	static void class_inherit(bparser *parser, bexpdesc *e)
1421	{
1422	    if (next_type(parser) == OptColon) { /* ':' */
1423	        bexpdesc e1;
1424	        scan_next_token(parser); /* skip ':' */
1425	        expr(parser, &e1);
1426	        check_var(parser, &e1);
1427	        be_code_setsuper(parser->finfo, e, &e1);
