1662	static void mainfunc(bparser *parser, bclosure *cl)
1663	{
1664	    bblockinfo binfo;
1665	    bfuncinfo finfo;
1666	    begin_func(parser, &finfo, &binfo);
1667	    finfo.proto->argc = 0; /* args */
1668	    finfo.proto->name = be_newstr(parser->vm, funcname(parser));
1669	    cl->proto = finfo.proto;
1670	    be_remove(parser->vm, -3);  /* pop proto from stack */
1671	    stmtlist(parser);
1672	    end_func(parser);
1673	    match_token(parser, TokenEOS); /* skip EOS */
1674	}
