1676	bclosure* be_parser_source(bvm *vm,
1677	    const char *fname, breader reader, void *data, bbool islocal)
1678	{
1679	    bparser parser;
1680	    bclosure *cl = be_newclosure(vm, 0);
1681	    parser.vm = vm;
1682	    parser.finfo = NULL;
1683	    parser.cl = cl;
1684	    parser.islocal = (bbyte)islocal;
1685	    var_setclosure(vm->top, cl);
1686	    be_stackpush(vm);
1687	    be_lexer_init(&parser.lexer, vm, fname, reader, data);
1688	    scan_next_token(&parser); /* scan first token */
1689	    mainfunc(&parser, cl);
1690	    be_lexer_deinit(&parser.lexer);
1691	    be_global_release_space(vm); /* clear global space */
1692	    be_stackpop(vm, 2); /* pop strtab */
1693	    scan_next_token(&parser); /* clear lexer */
1694	    return cl;
1695	}
