 59	/* Add new instruction in the code vector */
 60	static int codeinst(bfuncinfo *finfo, binstruction ins)
 61	{
 62	    /* put new instruction in code array */
 63	    be_vector_push_c(finfo->lexer->vm, &finfo->code, &ins);
 64	    finfo->proto->code = be_vector_data(&finfo->code);
 65	    finfo->proto->codesize = be_vector_capacity(&finfo->code);
 66	    codelineinfo(finfo);
 67	    return finfo->pc++;
 68	}
