 70	static int codeABC(bfuncinfo *finfo, bopcode op, int a, int b, int c)
 71	{
 72	    return codeinst(finfo, ISET_OP(op)
 73	        | ISET_RA(a) | ISET_RKB(b) | ISET_RKC(c));
 74	}
 75	
 76	static int codeABx(bfuncinfo *finfo, bopcode op, int a, int bx)
 77	{
 78	    return codeinst(finfo, ISET_OP(op) | ISET_RA(a) | ISET_Bx(bx));
 79	}
