128	/* Allocate `count` registers at top of stack, update stack accordingly */
129	int be_code_allocregs(bfuncinfo *finfo, int count)
130	{
131	    int base = finfo->freereg;
132	    allocstack(finfo, count);
133	    finfo->freereg += (char)count;
134	    return base;
135	}
