377	/* idx: the proto index in proto_table
378	 * dst: the destination register
379	 **/
380	static void code_closure(bfuncinfo *finfo, int idx, int dst)
381	{
382	    codeABx(finfo, OP_CLOSURE, dst, idx); /* load closure to register */
383	}
