398	/* Compute variable from an expdesc */
399	/* Return constant index, or existing register or fallback to dst */
400	/* At exit, If dst is `freereg`, the register is allocated */
401	static int var2reg(bfuncinfo *finfo, bexpdesc *e, int dst)
402	{
403	    if (dst < 0) {  /* if unspecified, allocate a new register if needed */
404	        dst = finfo->freereg;
405	    }
406	    be_assert(e != NULL);
407	    switch (e->type) {
408	    case ETINT:
409	        if (constint(finfo, e->v.i)) {
410	            return exp2const(finfo, e);
411	        } else {
412	            codeABx(finfo, OP_LDINT, dst, var_toidx(e) + IsBx_MAX);
413	        }
414	        break;
415	    case ETBOOL:
416	        code_bool(finfo, dst, e->v.i != 0, 0);
417	        break;
418	    case ETNIL:
419	        codeABx(finfo, OP_LDNIL, dst, 0);
420	        break;
421	    case ETREAL:
422	    case ETSTRING:
423	        return exp2const(finfo, e);
424	    case ETPROTO:
425	        code_closure(finfo, e->v.idx, dst);
426	        break;
427	    case ETGLOBAL:
428	        codeABx(finfo, OP_GETGBL, dst, e->v.idx);
429	        break;
430	    case ETNGLOBAL:
431	        codeABC(finfo, OP_GETNGBL, dst, e->v.ss.idx, 0);
432	        break;
433	    case ETUPVAL:
434	        codeABx(finfo, OP_GETUPV, dst, e->v.idx);
435	        break;
436	    case ETMEMBER:
437	        dst = code_suffix(finfo, OP_GETMBR, e, dst);
438	        break;
439	    case ETINDEX:
440	        dst = code_suffix(finfo, OP_GETIDX, e, dst);
441	        break;
442	    case ETLOCAL: case ETREG: case ETCONST:
443	        return e->v.idx;
444	    default:
445	        return dst; /* error */
446	    }
447	    if (dst == finfo->freereg) { /* use a new register */
448	        be_code_allocregs(finfo, 1);
449	    }
450	    e->type = ETREG;
451	    e->v.idx = dst;
452	    return dst;
453	}
454	
455	static int exp2reg(bfuncinfo *finfo, bexpdesc *e, int dst)
456	{
457	    int reg = var2reg(finfo, e, dst);
458	    if (hasjump(e)) { /* if conditional expression */
459	        int pcf = NO_JUMP;  /* position of an eventual LOAD false */
460	        int pct = NO_JUMP;  /* position of an eventual LOAD true */
461	        int jpt = appendjump(finfo, jumpboolop(e, 1), e);
462	        reg = e->v.idx;
463	        be_code_conjump(finfo, &e->t, jpt);
464	        pcf = code_bool(finfo, reg, 0, 1);
465	        pct = code_bool(finfo, reg, 1, 0);
466	        patchlistaux(finfo, e->f, finfo->pc, pcf);
467	        patchlistaux(finfo, e->t, finfo->pc, pct);
468	        e->t = NO_JUMP;
469	        e->f = NO_JUMP;
470	        e->not = 0;
471	    }
472	    return reg;
473	}
474	
475	/* Select dest registers from both expressions */
476	/* If one of them is already a register, keep it */
477	/* If e1 or e2 are registers, we keep the lowest and free the highest (that must be at top) */
478	/* If none is a register, allocate a new one */
479	/* Returns the destination register, guaranteed to be ETREG */
480	static int codedestreg(bfuncinfo *finfo, bexpdesc *e1, bexpdesc *e2, int dst)
481	{
482	    int cand_dst = dst;
483	    int con1 = e1->type == ETREG, con2 = e2->type == ETREG;
484	
485	    if (con1 && con2) {
486	        cand_dst = min(e1->v.idx, e2->v.idx);
487	        be_code_freeregs(finfo, 1);
488	    } else if (con1) {
489	        cand_dst = e1->v.idx;
490	    } else if (con2) {
491	        cand_dst = e2->v.idx;
492	    } else {
493	        if (dst >= finfo->freereg) {
494	            cand_dst = be_code_allocregs(finfo, 1);
495	            return cand_dst;
496	        }
497	    }
498	    if (dst >= finfo->freereg) {
499	        return cand_dst;
500	    } else {
501	        return dst;
502	    }
503	}
